+import SwiftUI
+import Cocoa
+import GhosttyKit
+
+// MARK: - GhosttyTerminal
+
+/// ObservableObject that manages the Ghostty terminal state
+@MainActor
+class GhosttyTerminal: NSObject, ObservableObject {
+    @Published var isReady: Bool = false
+    @Published var errorMessage: String?
+
+    private var config: ghostty_config_t?
+    private var app: ghostty_app_t?
+    private(set) var surface: ghostty_surface_t?
+
+    /// Flag to track if Ghostty runtime was initialized
+    private static var ghosttyInitialized = false
+
+    override init() {
+        super.init()
+
+        // Initialize Ghostty runtime (only once)
+        if !Self.ghosttyInitialized {
+            let result = ghostty_init(0, nil)
+            if result != GHOSTTY_SUCCESS {
+                errorMessage = "Failed to initialize Ghostty runtime (code: \(result))"
+                return
+            }
+            Self.ghosttyInitialized = true
+        }
+
+        initializeGhostty()
+    }
+
+    deinit {
+        // Cleanup on deinit - direct calls since we own these pointers
+        if let surface = self.surface {
+            ghostty_surface_free(surface)
+        }
+        if let app = self.app {
+            ghostty_app_free(app)
+        }
+        if let config = self.config {
+            ghostty_config_free(config)
+        }
+    }
+
+    private func initializeGhostty() {
+        // Create config
+        guard let cfg = ghostty_config_new() else {
+            errorMessage = "Failed to create Ghostty config"
+            return
+        }
+        self.config = cfg
+
+        // Finalize config to apply defaults
+        ghostty_config_finalize(cfg)
+
+        // Create runtime config with callbacks
+        var runtimeConfig = ghostty_runtime_config_s(
+            userdata: Unmanaged.passUnretained(self).toOpaque(),
+            supports_selection_clipboard: true,
+            wakeup_cb: { userdata in
+                // Wakeup callback - trigger app tick on main thread
+                guard let userdata = userdata else { return }
+                let terminal = Unmanaged<GhosttyTerminal>.fromOpaque(userdata).takeUnretainedValue()
+                DispatchQueue.main.async {
+                    terminal.tick()
+                }
+            },
+            action_cb: { app, target, action in
+                // Handle actions from Ghostty
+                return false
+            },
+            read_clipboard_cb: { userdata, location, state in
+                // Read from clipboard
+                guard let userdata = userdata else { return }
+                let terminal = Unmanaged<GhosttyTerminal>.fromOpaque(userdata).takeUnretainedValue()
+                DispatchQueue.main.async {
+                    terminal.readClipboard(location: location, state: state)
+                }
+            },
+            confirm_read_clipboard_cb: { userdata, string, state, request in
+                // Confirm clipboard read
+            },
+            write_clipboard_cb: { userdata, location, content, len, confirm in
+                // Write to clipboard
+                guard let userdata = userdata else { return }
+                let terminal = Unmanaged<GhosttyTerminal>.fromOpaque(userdata).takeUnretainedValue()
+                DispatchQueue.main.async {
+                    terminal.writeClipboard(location: location, content: content, len: len)
+                }
+            },
+            close_surface_cb: { userdata, processAlive in
+                // Surface closed
+                guard let userdata = userdata else { return }
+                let terminal = Unmanaged<GhosttyTerminal>.fromOpaque(userdata).takeUnretainedValue()
+                DispatchQueue.main.async {
+                    terminal.surfaceClosed(processAlive: processAlive)
+                }
+            }
+        )
+
+        // Create the app
+        guard let ghosttyApp = ghostty_app_new(&runtimeConfig, cfg) else {
+            errorMessage = "Failed to create Ghostty app"
+            ghostty_config_free(cfg)
+            self.config = nil
+            return
+        }
+        self.app = ghosttyApp
+
+        isReady = true
+    }
+
+    /// Create a surface attached to the given NSView
+    func createSurface(in view: NSView, scaleFactor: Double = 2.0) -> Bool {
+        guard let app = self.app else { return false }
+
+        // Create surface config
+        var surfaceConfig = ghostty_surface_config_new()
+        surfaceConfig.platform_tag = GHOSTTY_PLATFORM_MACOS
+        surfaceConfig.platform.macos.nsview = Unmanaged.passUnretained(view).toOpaque()
+        surfaceConfig.userdata = Unmanaged.passUnretained(self).toOpaque()
+        surfaceConfig.scale_factor = scaleFactor
+        surfaceConfig.font_size = 0 // Use config default
+
+        // Create surface
+        guard let surface = ghostty_surface_new(app, &surfaceConfig) else {
+            errorMessage = "Failed to create Ghostty surface"
+            return false
+        }
+
+        self.surface = surface
+        return true
+    }
+
+    /// Called by the runtime to tick the app
+    func tick() {
+        guard let app = self.app else { return }
+        ghostty_app_tick(app)
+    }
+
+    /// Handle resize
+    func resize(width: UInt32, height: UInt32) {
+        guard let surface = self.surface else { return }
+        ghostty_surface_set_size(surface, width, height)
+    }
+
+    /// Set focus state
+    func setFocus(_ focused: Bool) {
+        guard let surface = self.surface else { return }
+        ghostty_surface_set_focus(surface, focused)
+    }
+
+    /// Refresh/redraw
+    func refresh() {
+        guard let surface = self.surface else { return }
+        ghostty_surface_refresh(surface)
+    }
+
+    /// Draw the terminal
+    func draw() {
+        guard let surface = self.surface else { return }
+        ghostty_surface_draw(surface)
+    }
+
+    /// Handle key input
+    func handleKey(action: ghostty_input_action_e, mods: ghostty_input_mods_e,
+                   keycode: UInt32, text: String?) -> Bool {
+        guard let surface = self.surface else { return false }
+
+        var keyInput = ghostty_input_key_s()
+        keyInput.action = action
+        keyInput.mods = mods
+        keyInput.consumed_mods = GHOSTTY_MODS_NONE
+        keyInput.keycode = keycode
+        keyInput.composing = false
+
+        if let text = text {
+            return text.withCString { ptr in
+                keyInput.text = ptr
+                return ghostty_surface_key(surface, keyInput)
+            }
+        } else {
+            keyInput.text = nil
+            return ghostty_surface_key(surface, keyInput)
+        }
+    }
+
+    /// Handle text input
+    func handleText(_ text: String) {
+        guard let surface = self.surface else { return }
+        text.withCString { ptr in
+            ghostty_surface_text(surface, ptr, UInt(text.utf8.count))
+        }
+    }
+
+    /// Handle mouse button
+    func handleMouseButton(state: ghostty_input_mouse_state_e,
+                           button: ghostty_input_mouse_button_e,
+                           mods: ghostty_input_mods_e) -> Bool {
+        guard let surface = self.surface else { return false }
+        return ghostty_surface_mouse_button(surface, state, button, mods)
+    }
+
+    /// Handle mouse position
+    func handleMousePos(x: Double, y: Double, mods: ghostty_input_mods_e) {
+        guard let surface = self.surface else { return }
+        ghostty_surface_mouse_pos(surface, x, y, mods)
+    }
+
+    /// Handle mouse scroll
+    func handleMouseScroll(deltaX: Double, deltaY: Double, mods: ghostty_input_scroll_mods_t) {
+        guard let surface = self.surface else { return }
+        ghostty_surface_mouse_scroll(surface, deltaX, deltaY, mods)
+    }
+
+    /// Read from clipboard
+    private func readClipboard(location: ghostty_clipboard_e, state: UnsafeMutableRawPointer?) {
+        guard let surface = self.surface else { return }
+
+        let pasteboard = NSPasteboard.general
+        let str = pasteboard.string(forType: .string) ?? ""
+
+        str.withCString { ptr in
+            ghostty_surface_complete_clipboard_request(surface, ptr, state, false)
+        }
+    }
+
+    /// Write to clipboard
+    private func writeClipboard(location: ghostty_clipboard_e,
+                                 content: UnsafePointer<ghostty_clipboard_content_s>?,
+                                 len: Int) {
+        // Safety checks
+        guard len > 0, let content = content else { return }
+
+        // Only handle standard clipboard, not selection
+        guard location == GHOSTTY_CLIPBOARD_STANDARD else { return }
+
+        // Iterate through content items safely
+        for i in 0..<len {
+            let item = content[i]
+
+            // Safely extract strings - skip if nil
+            guard let mimePtr = item.mime, let dataPtr = item.data else { continue }
+
+            // Safely convert to strings
+            let mimeStr = String(cString: mimePtr)
+            let dataStr = String(cString: dataPtr)
+
+            if mimeStr == "text/plain" {
+                let pasteboard = NSPasteboard.general
+                pasteboard.clearContents()
+                pasteboard.setString(dataStr, forType: .string)
+                return // Only set first text/plain
+            }
+        }
+    }
+
+    /// Surface closed callback
+    private func surfaceClosed(processAlive: Bool) {
+        // Handle surface close
+        self.surface = nil
+    }
+
+}
