+// MARK: - GhosttyNSView
+
+/// Native NSView that hosts the Ghostty Metal terminal
+class GhosttyNSView: NSView {
+    private weak var terminal: GhosttyTerminal?
+    private var displayLink: CVDisplayLink?
+    private var surfaceCreated = false
+
+    init(terminal: GhosttyTerminal) {
+        self.terminal = terminal
+        super.init(frame: .zero)
+        setup()
+    }
+
+    required init?(coder: NSCoder) {
+        fatalError("init(coder:) not implemented")
+    }
+
+    deinit {
+        stopDisplayLink()
+    }
+
+    private func setup() {
+        wantsLayer = true
+        layer?.backgroundColor = NSColor(red: 0.08, green: 0.08, blue: 0.1, alpha: 1).cgColor
+    }
+
+    override func viewDidMoveToWindow() {
+        super.viewDidMoveToWindow()
+
+        if window != nil && !surfaceCreated {
+            createSurface()
+        }
+    }
+
+    private func createSurface() {
+        guard let terminal = terminal, terminal.isReady else { return }
+
+        // Get scale factor
+        let scale = window?.backingScaleFactor ?? 2.0
+
+        if terminal.createSurface(in: self, scaleFactor: scale) {
+            surfaceCreated = true
+
+            // Initial size
+            let size = convertToBacking(bounds.size)
+            terminal.resize(width: UInt32(size.width), height: UInt32(size.height))
+            terminal.setFocus(true)
+
+            // Start display link for rendering
+            startDisplayLink()
+        }
+    }
+
+    private func startDisplayLink() {
+        guard displayLink == nil else { return }
+
+        CVDisplayLinkCreateWithActiveCGDisplays(&displayLink)
+        guard let displayLink = displayLink else { return }
+
+        let callback: CVDisplayLinkOutputCallback = { _, _, _, _, _, userInfo in
+            guard let userInfo = userInfo else { return kCVReturnSuccess }
+            let view = Unmanaged<GhosttyNSView>.fromOpaque(userInfo).takeUnretainedValue()
+            DispatchQueue.main.async {
+                view.terminal?.draw()
+            }
+            return kCVReturnSuccess
+        }
+
+        CVDisplayLinkSetOutputCallback(displayLink, callback,
+                                       Unmanaged.passUnretained(self).toOpaque())
+        CVDisplayLinkStart(displayLink)
+    }
+
+    private func stopDisplayLink() {
+        guard let displayLink = displayLink else { return }
+        CVDisplayLinkStop(displayLink)
+        self.displayLink = nil
+    }
+
+    override func layout() {
+        super.layout()
+
+        guard surfaceCreated, let terminal = terminal else { return }
+
+        let size = convertToBacking(bounds.size)
+        terminal.resize(width: UInt32(size.width), height: UInt32(size.height))
+    }
+
+    override var acceptsFirstResponder: Bool { true }
+
+    override func becomeFirstResponder() -> Bool {
+        terminal?.setFocus(true)
+        return super.becomeFirstResponder()
+    }
+
+    override func resignFirstResponder() -> Bool {
+        terminal?.setFocus(false)
+        return super.resignFirstResponder()
+    }
+
+    // MARK: - Keyboard Input
+
+    override func keyDown(with event: NSEvent) {
+        guard let terminal = terminal else {
+            super.keyDown(with: event)
+            return
+        }
+
+        let mods = convertModifiers(event.modifierFlags)
+        let keycode = event.keyCode
+
+        let handled = terminal.handleKey(
+            action: GHOSTTY_ACTION_PRESS,
+            mods: mods,
+            keycode: UInt32(keycode),
+            text: event.characters
+        )
+
+        if !handled {
+            // Let interpretKeyEvents handle text input
+            interpretKeyEvents([event])
+        }
+    }
+
+    override func keyUp(with event: NSEvent) {
+        guard let terminal = terminal else {
+            super.keyUp(with: event)
+            return
+        }
+
+        let mods = convertModifiers(event.modifierFlags)
+        let keycode = event.keyCode
+
+        _ = terminal.handleKey(
+            action: GHOSTTY_ACTION_RELEASE,
+            mods: mods,
+            keycode: UInt32(keycode),
+            text: nil
+        )
+    }
+
+    // MARK: - Mouse Input
+
+    override func mouseDown(with event: NSEvent) {
+        guard let terminal = terminal else { return }
+        let mods = convertModifiers(event.modifierFlags)
+        _ = terminal.handleMouseButton(state: GHOSTTY_MOUSE_PRESS, button: GHOSTTY_MOUSE_LEFT, mods: mods)
+    }
+
+    override func mouseUp(with event: NSEvent) {
+        guard let terminal = terminal else { return }
+        let mods = convertModifiers(event.modifierFlags)
+        _ = terminal.handleMouseButton(state: GHOSTTY_MOUSE_RELEASE, button: GHOSTTY_MOUSE_LEFT, mods: mods)
+    }
+
+    override func rightMouseDown(with event: NSEvent) {
+        guard let terminal = terminal else { return }
+        let mods = convertModifiers(event.modifierFlags)
+        _ = terminal.handleMouseButton(state: GHOSTTY_MOUSE_PRESS, button: GHOSTTY_MOUSE_RIGHT, mods: mods)
+    }
+
+    override func rightMouseUp(with event: NSEvent) {
+        guard let terminal = terminal else { return }
+        let mods = convertModifiers(event.modifierFlags)
+        _ = terminal.handleMouseButton(state: GHOSTTY_MOUSE_RELEASE, button: GHOSTTY_MOUSE_RIGHT, mods: mods)
+    }
+
+    override func mouseMoved(with event: NSEvent) {
+        handleMouseMoved(event)
+    }
+
+    override func mouseDragged(with event: NSEvent) {
+        handleMouseMoved(event)
+    }
+
+    private func handleMouseMoved(_ event: NSEvent) {
+        guard let terminal = terminal else { return }
+        let point = convert(event.locationInWindow, from: nil)
+        let mods = convertModifiers(event.modifierFlags)
+        terminal.handleMousePos(x: point.x, y: bounds.height - point.y, mods: mods)
+    }
+
+    override func scrollWheel(with event: NSEvent) {
+        guard let terminal = terminal else { return }
+
+        var scrollMods: ghostty_input_scroll_mods_t = 0
+        // Build scroll mods from event
+        if event.hasPreciseScrollingDeltas {
+            scrollMods |= 1 // Precise scrolling flag
+        }
+
+        terminal.handleMouseScroll(
+            deltaX: event.scrollingDeltaX,
+            deltaY: event.scrollingDeltaY,
+            mods: scrollMods
+        )
+    }
+
+    // MARK: - Helpers
+
+    private func convertModifiers(_ flags: NSEvent.ModifierFlags) -> ghostty_input_mods_e {
+        var mods = GHOSTTY_MODS_NONE
+
+        if flags.contains(.shift) {
+            mods = ghostty_input_mods_e(rawValue: mods.rawValue | GHOSTTY_MODS_SHIFT.rawValue)
+        }
+        if flags.contains(.control) {
+            mods = ghostty_input_mods_e(rawValue: mods.rawValue | GHOSTTY_MODS_CTRL.rawValue)
+        }
+        if flags.contains(.option) {
+            mods = ghostty_input_mods_e(rawValue: mods.rawValue | GHOSTTY_MODS_ALT.rawValue)
+        }
+        if flags.contains(.command) {
+            mods = ghostty_input_mods_e(rawValue: mods.rawValue | GHOSTTY_MODS_SUPER.rawValue)
+        }
+        if flags.contains(.capsLock) {
+            mods = ghostty_input_mods_e(rawValue: mods.rawValue | GHOSTTY_MODS_CAPS.rawValue)
+        }
+
+        return mods
+    }
+}
+
+// MARK: - NSTextInputClient
+
+extension GhosttyNSView: NSTextInputClient {
+    func insertText(_ string: Any, replacementRange: NSRange) {
+        guard let terminal = terminal, let text = string as? String else { return }
+        terminal.handleText(text)
+    }
+
+    func setMarkedText(_ string: Any, selectedRange: NSRange, replacementRange: NSRange) {
+        // Handle IME marked text
+        guard let surface = terminal?.surface else { return }
+
+        let text: String
+        if let str = string as? String {
+            text = str
+        } else if let attrStr = string as? NSAttributedString {
+            text = attrStr.string
+        } else {
+            return
+        }
+
+        text.withCString { ptr in
+            ghostty_surface_preedit(surface, ptr, UInt(text.utf8.count))
+        }
+    }
+
+    func unmarkText() {
+        guard let surface = terminal?.surface else { return }
+        ghostty_surface_preedit(surface, nil, 0)
+    }
+
+    func selectedRange() -> NSRange {
+        return NSRange(location: NSNotFound, length: 0)
+    }
+
+    func markedRange() -> NSRange {
+        return NSRange(location: NSNotFound, length: 0)
+    }
+
+    func hasMarkedText() -> Bool {
+        return false
+    }
+
+    func attributedSubstring(forProposedRange range: NSRange, actualRange: NSRangePointer?) -> NSAttributedString? {
+        return nil
+    }
+
+    func validAttributesForMarkedText() -> [NSAttributedString.Key] {
+        return []
+    }
+
+    func firstRect(forCharacterRange range: NSRange, actualRange: NSRangePointer?) -> NSRect {
+        guard let surface = terminal?.surface else { return .zero }
+
+        var x: Double = 0, y: Double = 0, w: Double = 0, h: Double = 0
+        ghostty_surface_ime_point(surface, &x, &y, &w, &h)
+
+        // Convert from backing coordinates
+        let point = convertFromBacking(NSPoint(x: x, y: y))
+        let size = convertFromBacking(NSSize(width: w, height: h))
+
+        // Convert to screen coordinates
+        var rect = NSRect(origin: point, size: size)
+        if let window = window {
+            rect = window.convertToScreen(convert(rect, to: nil))
+        }
+
+        return rect
+    }
+
+    func characterIndex(for point: NSPoint) -> Int {
+        return NSNotFound
+    }
+}

