+// MARK: - HybridNSView
+
+/// Container that manages Ghostty (bottom) + WebKit overlay (top) layers
+class HybridNSView: NSView {
+    private weak var terminal: GhosttyTerminal?
+    private var ghosttyView: GhosttyNSView!
+    private var overlayView: OverlayWebView!
+
+    /// The hole rect in view coordinates where clicks pass through to Ghostty
+    var holeRect: NSRect = .zero
+
+    init(terminal: GhosttyTerminal) {
+        self.terminal = terminal
+        super.init(frame: .zero)
+        setup()
+    }
+
+    required init?(coder: NSCoder) {
+        fatalError("init(coder:) not implemented")
+    }
+
+    private func setup() {
+        wantsLayer = true
+        layer?.backgroundColor = NSColor(red: 0.08, green: 0.08, blue: 0.1, alpha: 1).cgColor
+
+        // Layer 1 (Bottom): Ghostty Metal terminal
+        ghosttyView = GhosttyNSView(terminal: terminal!)
+        ghosttyView.translatesAutoresizingMaskIntoConstraints = false
+        addSubview(ghosttyView)
+
+        // Layer 2 (Top): WebKit overlay
+        let config = WKWebViewConfiguration()
+        config.userContentController.add(WeakScriptMessageHandler(self), name: "holePunch")
+        config.userContentController.add(WeakScriptMessageHandler(self), name: "zell")
+
+        overlayView = OverlayWebView(frame: .zero, configuration: config)
+        overlayView.translatesAutoresizingMaskIntoConstraints = false
+        overlayView.containerView = self
+        addSubview(overlayView)
+
+        // Constraints - both views fill the container
+        NSLayoutConstraint.activate([
+            ghosttyView.topAnchor.constraint(equalTo: topAnchor),
+            ghosttyView.leadingAnchor.constraint(equalTo: leadingAnchor),
+            ghosttyView.trailingAnchor.constraint(equalTo: trailingAnchor),
+            ghosttyView.bottomAnchor.constraint(equalTo: bottomAnchor),
+
+            overlayView.topAnchor.constraint(equalTo: topAnchor),
+            overlayView.leadingAnchor.constraint(equalTo: leadingAnchor),
+            overlayView.trailingAnchor.constraint(equalTo: trailingAnchor),
+            overlayView.bottomAnchor.constraint(equalTo: bottomAnchor),
+        ])
+
+        // Load overlay HTML
+        loadOverlay()
+    }
+
+    private func loadOverlay() {
+        if let url = Bundle.main.url(forResource: "overlay", withExtension: "html", subdirectory: "Resources") {
+            overlayView.loadFileURL(url, allowingReadAccessTo: url.deletingLastPathComponent())
+        } else {
+            // Fallback: load inline HTML
+            let html = Self.inlineOverlayHTML
+            overlayView.loadHTMLString(html, baseURL: nil)
+        }
+    }
+
+    /// Update the hole rect from JavaScript coordinates
+    func updateHoleRect(x: CGFloat, y: CGFloat, width: CGFloat, height: CGFloat) {
+        // JavaScript gives us coordinates with origin at top-left
+        // NSView has origin at bottom-left, so flip Y
+        let flippedY = bounds.height - y - height
+        holeRect = NSRect(x: x, y: flippedY, width: width, height: height)
+        overlayView.holeRect = holeRect
+    }
+
+    // MARK: - Inline HTML fallback
+
+    static let inlineOverlayHTML = """
+    <!DOCTYPE html>
+    <html>
+    <head>
+        <style>
+            * { margin: 0; padding: 0; box-sizing: border-box; }
+            html, body {
+                background: transparent;
+                font-family: -apple-system, BlinkMacSystemFont, sans-serif;
+                color: white;
+                overflow: hidden;
+                height: 100%;
+            }
+            .container {
+                display: grid;
+                grid-template-rows: 48px 1fr 80px;
+                height: 100vh;
