+// MARK: - WKScriptMessageHandler
+
+extension HybridNSView: WKScriptMessageHandler {
+    func userContentController(_ userContentController: WKUserContentController,
+                               didReceive message: WKScriptMessage) {
+        guard let body = message.body as? [String: Any] else { return }
+
+        switch message.name {
+        case "holePunch":
+            if let x = body["x"] as? CGFloat,
+               let y = body["y"] as? CGFloat,
+               let w = body["width"] as? CGFloat,
+               let h = body["height"] as? CGFloat {
+                updateHoleRect(x: x, y: y, width: w, height: h)
+            }
+
+        case "zell":
+            if let type = body["type"] as? String, type == "prompt",
+               let text = body["text"] as? String {
+                handlePrompt(text)
+            }
+
+        default:
+            break
+        }
+    }
+
+    private func handlePrompt(_ text: String) {
+        // Send text to terminal
+        terminal?.handleText(text + "\n")
+    }
+}
