+// MARK: - OverlayWebView
+
+/// WKWebView with transparent background and hole punch support
+class OverlayWebView: WKWebView {
+    weak var containerView: HybridNSView?
+    var holeRect: NSRect = .zero
+
+    override init(frame: CGRect, configuration: WKWebViewConfiguration) {
+        super.init(frame: frame, configuration: configuration)
+        setupTransparency()
+    }
+
+    required init?(coder: NSCoder) {
+        fatalError("init(coder:) not implemented")
+    }
+
+    private func setupTransparency() {
+        // Make WebView transparent
+        setValue(false, forKey: "drawsBackground")
+    }
+
+    // CRITICAL: Override hitTest to pass clicks through the hole to Ghostty
+    override func hitTest(_ point: NSPoint) -> NSView? {
+        // If click is inside the hole, return nil to pass through to Ghostty
+        if holeRect.contains(point) {
+            return nil
+        }
+        return super.hitTest(point)
+    }
+}
